payload.raw:
{
  "layout": "text-image",
  "title": "创新设计：研究内容",
  "subtitle": "四大研究方向",
  "body": [
    {
      "type": "bullet",
      "items": [
        "材料创新：基于仿水膜-鱼网结构的液态金属基导电薄膜与低迟滞聚氨酯介质复合材料，构建高灵敏度、低迟滞的柔性传感体系。",
        "传感架构：融合光纤传感与惯性测量单元（IMU），形成混合传感架构，实现0.1mm级高空间分辨率。",
        "算法核心：开发轻量化分层手势识别模型，结合时序滑动窗口与噪声抑制，实现毫秒级实时推理与高鲁棒性（实测准确率>98.2%）。",
        "系统集成：集成多模态交互协议栈，嵌入压力/温度动态反馈执行单元，构建感知-意图-反馈的完整交互闭环。"
      ]
    }
  ],
  "image": {
    "prompt": "A detailed technical framework diagram showing the four research directions of a smart data glove: material innovation with liquid metal composite films, hybrid sensing architecture combining optical fiber and IMU, hierarchical AI algorithm model, and system integration with haptic feedback modules, all interconnected in a clear flow.",
    "alt": "龙影数据手套四大研究方向技术框架图"
  }
}

